// Store config in workflow context and set date range
const configData = $input.first().json;
const today = new Date();
const yesterday = new Date(today);
yesterday.setDate(yesterday.getDate() - 1);
const fmt = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    startdt: fmt(yesterday),
    enddt: fmt(today),
    _config: configData.config || {}
  }
}];

// Parse EFTS response and extract filing data
const dateRangeData = $('Set Date Range').first().json;
const config = dateRangeData._config || {};

const data = $input.first().json;
const hits = data.hits?.hits || [];

if (hits.length === 0) {
  return [{ json: { _skip: true, message: 'No filings found', _config: config } }];
}

// Group by CIK, prefer D/A amendments
const entityMap = new Map();
for (const h of hits) {
  const cik = h._source.ciks?.[0];
  if (!cik) continue;
  const existing = entityMap.get(cik);
  if (!existing || h._source.form === 'D/A') entityMap.set(cik, h);
}

return Array.from(entityMap.values()).map(h => {
  const src = h._source;
  const cik = src.ciks?.[0] || '';
  const cikNum = cik.replace(/^0+/, '');
  const adsh = src.adsh || '';
  const adshNoDashes = adsh.replace(/-/g, '');
  let entityName = src.display_names?.[0] || 'Unknown';
  entityName = entityName.replace(/\s*\(CIK\s*\d+\)\s*$/i, '').trim();
  const filePath = `Archives/edgar/data/${cikNum}/${adshNoDashes}/primary_doc.xml`;
  return {
    json: {
      entityName,
      cik,
      filePath,
      fileDate: src.file_date,
      formType: src.form || src.file_type,
      location: src.biz_locations || 'unknown',
      _config: config
    }
  };
});

// v2.3: Prepare Form D data for Dedup Check subworkflow
// Dedup Check expects: company, title, recordType, source, _originalJobData
const input = $json;

return {
  json: {
    // Fields expected by Dedup Check
    company: input.entityName || '',
    title: '',  // Form D filings don't have job titles
    recordType: 'company',
    source: 'SEC Form D',
    // Store ALL original Form D data in _originalJobData (preserved by Dedup Check)
    _originalJobData: {
      entityName: input.entityName,
      cik: input.cik,
      filePath: input.filePath,
      fileDate: input.fileDate,
      formType: input.formType,
      location: input.location,
      _config: input._config
    }
  }
};

// v2.3: Recover Form D data after Dedup Check
// Dedup Check returns: isDuplicate, key, _originalJobData
// We need to: map isDuplicate -> isNew, recover Form D fields
const input = $json;
const formDData = input._originalJobData || {};

return {
  json: {
    // Map isDuplicate to isNew (inverted)
    isNew: input.isDuplicate === false,
    isDuplicate: input.isDuplicate,
    dedupKey: input.key,
    // Recover all Form D fields
    entityName: formDData.entityName,
    cik: formDData.cik,
    filePath: formDData.filePath,
    fileDate: formDData.fileDate,
    formType: formDData.formType,
    location: formDData.location,
    _config: formDData._config
  }
};

// Parse Form D XML and extract key fields
// v2.3: Input should have all Form D fields preserved by HTTP node (outputPropertyName)
const originalItems = $('Filter New Only').all();
const xmlItems = $input.all();

// Build lookup map by filePath for safe matching
const originalByPath = new Map();
for (const orig of originalItems) {
  if (orig.json.filePath) {
    originalByPath.set(orig.json.filePath, orig.json);
  }
}

return xmlItems.map((item, index) => {
  const xml = item.json.data || item.json.xmlData || item.json.body || '';

  // Get original data - HTTP node with outputPropertyName should preserve input
  let original = {};
  if (item.json.filePath && item.json._config) {
    // HTTP node preserved input - use directly
    original = item.json;
  } else if (item.json.filePath && originalByPath.has(item.json.filePath)) {
    // Match by filePath (safe)
    original = originalByPath.get(item.json.filePath);
  } else {
    // Fallback to index
    original = originalItems[index]?.json || {};
    console.log('WARNING: Using index-based fallback for item ' + index);
  }

  function extract(tag) {
    const patterns = [
      new RegExp('<' + tag + '>([^<]*)</' + tag + '>', 'i'),
      new RegExp('<com:' + tag + '>([^<]*)</com:' + tag + '>', 'i')
    ];
    for (const p of patterns) {
      const m = xml.match(p);
      if (m) return m[1].trim();
    }
    return null;
  }

  const issuerName = extract('issuerName') || original.entityName || 'Unknown';
  const industryGroup = extract('industryGroupType');
  const totalOffering = parseFloat(extract('totalOfferingAmount')) || 0;
  const totalSold = parseFloat(extract('totalAmountSold')) || 0;
  const yearOfIncorp = extract('yearOfIncorporation');
  const state = extract('issuerState');
  const city = extract('issuerCity');
  const fundingAmount = totalOffering > 0 ? totalOffering : totalSold;

  if (!issuerName || issuerName === 'Unknown') {
    console.log('WARNING: Failed to extract issuerName from XML for ' + (original.filePath || 'unknown'));
  }

  return {
    json: {
      issuerName,
      industryGroup,
      fundingAmount,
      totalSold,
      yearOfIncorp,
      state,
      city,
      cik: original.cik,
      fileDate: original.fileDate,
      formType: original.formType,
      filePath: original.filePath,
      _config: original._config
    }
  };
});

// Pre-filter Form D filings based on config-driven criteria
const items = $input.all();
const results = [];

// Get config from first item (carried through from Fetch Config)
const config = items[0]?.json._config || {};

const FUNDING_MIN = config.FORM_D_FUNDING_MIN || 5000000;
const FUNDING_MAX = config.FUNDING_HARD_CAP || 75000000;
const AGE_HARD_CAP = config.COMPANY_AGE_HARD_CAP || 8;

const targetKeywords = [
  'health care', 'technology', 'biotechnology', 'biotech',
  'telecommunications', 'software', 'saas', 'ai',
  'artificial intelligence', 'machine learning', 'data',
  'cloud', 'cyber', 'medical', 'pharma', 'therapeutic', 'diagnostic'
];

const excludeIndustries = [
  'Pooled Investment Fund', 'Real Estate', 'Residential', 'Commercial',
  'REITS', 'Oil & Gas', 'Energy', 'Mining', 'Agriculture',
  'Lodging & Conventions', 'Restaurants', 'Banking', 'Commercial Banking',
  'Insurance', 'Investing', 'Construction'
];

function isTargetIndustry(industry) {
  if (!industry) return true;
  if (industry === 'Other') return true;
  const lower = industry.toLowerCase();
  for (const ex of excludeIndustries) {
    if (lower.includes(ex.toLowerCase())) return false;
  }
  for (const kw of targetKeywords) {
    if (lower.includes(kw)) return true;
  }
  return false;
}

const currentYear = new Date().getFullYear();

for (const item of items) {
  const d = item.json;

  // Skip items with no funding data
  if (!d.fundingAmount && !d.totalSold) continue;

  // Funding gate
  if (d.fundingAmount < FUNDING_MIN || d.fundingAmount > FUNDING_MAX) continue;

  // Industry gate
  if (!isTargetIndustry(d.industryGroup)) continue;

  // US only
  if (d.state && d.state.length !== 2) continue;

  // Age gate
  if (d.yearOfIncorp && (currentYear - parseInt(d.yearOfIncorp)) > AGE_HARD_CAP) continue;

  // Infer stage from funding amount
  let inferredStage = 'Unknown';
  if (d.fundingAmount <= 10000000) inferredStage = 'Seed';
  else if (d.fundingAmount <= 30000000) inferredStage = 'Series A';
  else if (d.fundingAmount <= 75000000) inferredStage = 'Series B';

  results.push({
    json: {
      ...d,
      inferredStage,
      source: 'SEC Form D'
    }
  });
}

if (results.length === 0) return [];
return results;

// Format output for Enrich & Evaluate Pipeline input schema
// v2.4: Use lowercase 'source' (pipeline reads item.source)
const items = $input.all();

if (items.length === 0) return [];

return items.map(item => {
  const d = item.json;

  const parts = [];
  if (d.industryGroup) parts.push(d.industryGroup);
  if (d.city && d.state) parts.push(d.city + ', ' + d.state);
  if (d.inferredStage !== 'Unknown') parts.push(d.inferredStage);

  const fundingStr = (d.fundingAmount / 1000000).toFixed(1) + 'M';
  const description = d.issuerName + ' - SEC Form D filing. ' +
    fundingStr + ' raised. ' + parts.join('. ') + '.';

  // Build SEC EDGAR URL as fallback company URL
  const cikNum = d.cik ? d.cik.replace(/^0+/, '') : '';
  const secUrl = cikNum ? 'https://www.sec.gov/cgi-bin/browse-edgar?action=getcompany&CIK=' + cikNum : '';

  return {
    json: {
      'Company Name': d.issuerName,
      'Company URL': secUrl,
      'Company Description': description,
      'source': 'SEC Form D',
      'VC Firm': 'SEC Form D',
      'Total Funding': fundingStr,
      'Founded Year': d.yearOfIncorp ? parseInt(d.yearOfIncorp) : null,
      'Stage': d.inferredStage,
      'Employee Count': null
    }
  };
});
